/* Layout: the-new */
/* Scope: theme */
/* Generated by Layout Maker — do not edit manually */

/* ── Layout frame ── */
.layout-frame {
  width: 100%;
}

/* ── Layout background ── */
html, body {
  background: #FFFFFF;
}

/* ── Grid: desktop (1440px+) ── */
.layout-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
}

/* ── Slot: header ── */
[data-slot="header"] {
  display: flex;
  flex-direction: column;
}

/* ── Slot: content ── */
[data-slot="content"] {
  display: flex;
  flex-direction: column;
}

/* ── Slot: footer ── */
[data-slot="footer"] {
  display: flex;
  flex-direction: column;
}

/* ── Slot: sidebar-left ── */
[data-slot="sidebar-left"] {
  display: flex;
  flex-direction: column;
  min-height: 400px;
}

/* ── Slot: sidebar-right ── */
[data-slot="sidebar-right"] {
  display: flex;
  flex-direction: column;
  min-height: 400px;
}

/* ── Slot inner vars (base) ── */
:root {
  --sl-content-mw: 615px;
  --sl-content-px: 0;
  --sl-content-pt: 24px;
  --sl-content-pb: 24px;
  --sl-content-al: center;
  --sl-sidebar-left-mw: 360px;
  --sl-sidebar-left-pt: 24px;
  --sl-sidebar-left-pb: 24px;
  --sl-sidebar-left-al: center;
  --sl-sidebar-right-mw: 360px;
  --sl-sidebar-right-pt: 24px;
  --sl-sidebar-right-pb: 24px;
  --sl-sidebar-right-al: center;
}

[data-slot] > .slot-inner {
  display: flex;
  flex-direction: column;
  width: 100%;
  flex: 1 0 auto;
}

[data-slot="header"] > .slot-inner {
  max-width: var(--sl-header-mw, none);
  padding: var(--sl-header-pt, 0) var(--sl-header-px, 0) var(--sl-header-pb, 0);
  gap: var(--sl-header-gap, 0);
  align-self: var(--sl-header-al, stretch);
  margin-inline: auto;
}

[data-slot="content"] > .slot-inner {
  max-width: var(--sl-content-mw, none);
  padding: var(--sl-content-pt, 0) var(--sl-content-px, 0) var(--sl-content-pb, 0);
  gap: var(--sl-content-gap, 0);
  align-self: var(--sl-content-al, stretch);
  margin-inline: auto;
}

[data-slot="footer"] > .slot-inner {
  max-width: var(--sl-footer-mw, none);
  padding: var(--sl-footer-pt, 0) var(--sl-footer-px, 0) var(--sl-footer-pb, 0);
  gap: var(--sl-footer-gap, 0);
  align-self: var(--sl-footer-al, stretch);
  margin-inline: auto;
}

[data-slot="sidebar-left"] > .slot-inner {
  max-width: var(--sl-sidebar-left-mw, none);
  padding: var(--sl-sidebar-left-pt, 0) var(--sl-sidebar-left-px, 0) var(--sl-sidebar-left-pb, 0);
  gap: var(--sl-sidebar-left-gap, 0);
  align-self: var(--sl-sidebar-left-al, stretch);
  margin-inline: auto;
}

[data-slot="sidebar-right"] > .slot-inner {
  max-width: var(--sl-sidebar-right-mw, none);
  padding: var(--sl-sidebar-right-pt, 0) var(--sl-sidebar-right-px, 0) var(--sl-sidebar-right-pb, 0);
  gap: var(--sl-sidebar-right-gap, 0);
  align-self: var(--sl-sidebar-right-al, stretch);
  margin-inline: auto;
}
